INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.concept.title', 'Nuestra', 'Our', 'Notre') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.concept.titleEm', 'Misión', 'Mission', 'Mission') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.concept.p1', 'Expo México Mujer 2027 es una plataforma de encuentros internacionales que transforma el liderazgo mexicano en acciones concretas, creando oportunidades de desarrollo económico y fortaleciendo la identidad de México en el extranjero.', 'Expo Mexico Mujer 2027 is a platform for international encounters that transforms Mexican leadership into concrete actions, creating economic development opportunities and strengthening Mexico''s identity abroad.', 'Expo Mexique Femme 2027 est une plateforme de rencontres internationales qui transforme le leadership mexicain en actions concrètes, créant des opportunités de développement économique et renforçant l''identité du Mexique à l''étranger.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.concept.p2', 'Nuestra misión es fortalecer los puentes comerciales, culturales y sociales entre México y Canadá, consolidando una comunidad binacional que impulse el crecimiento de empresas, productos y talentos mexicanos.', 'Our mission is to strengthen commercial, cultural, and social bridges between Mexico and Canada, consolidating a binational community that drives the growth of Mexican businesses, products, and talents.', 'Notre mission est de renforcer les ponts commerciaux, culturels et sociaux entre le Mexique et le Canada, en consolidant une communauté binationale qui stimule la croissance des entreprises, produits et talents mexicains.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.audience.title', 'Esto es para quienes', 'This is for those who', 'C''est pour ceux qui') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.audience.titleEm', 'construyen puentes', 'build bridges', 'construisent des ponts') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.audience.desc', 'Un espacio diseñado para que cada visitante encuentre su lugar en la expo y defina su rol en esta historia binacional.', 'A space designed so each visitor finds their place at the expo and defines their role in this binational story.', 'Un espace conçu pour que chaque visiteur trouve sa place à l''expo et définisse son rôle dans cette histoire binationale.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.audience.item1', 'Emprendedoras buscando expandirse a Canadá', 'Entrepreneurs looking to expand to Canada', 'Entrepreneuses cherchant à s''étendre au Canada') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.audience.item2', 'Empresas que quieren patrocinar con propósito', 'Companies that want to sponsor with purpose', 'Entreprises qui veulent parrainer avec un but') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.audience.item3', 'Expositoras y compradores binacionales', 'Exhibitors and binational buyers', 'Exposantes et acheteurs binationales') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.audience.item4', 'Medios, cámaras y aliados institucionales', 'Media, chambers, and institutional allies', 'Médias, chambres et alliés institutionnels') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.audience.quote', 'La expo necesita una presencia que se sienta institucional, contemporánea y lista para convertir liderazgo en legado.', 'The expo needs a presence that feels institutional, contemporary, and ready to turn leadership into legacy.', 'L''expo a besoin d''une présence qui se sente institutionnelle, contemporaine et prête à convertir le leadership en héritage.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.audience.quoteAttr', '— Dirección creativa, EMM 2027', '— Creative Direction, EMM 2027', '— Direction créative, EMM 2027') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
