INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.agenda.day1Text', 'Bienvenida, presentación de visión binacional y encuentros con aliados estratégicos. Ceremonia inaugural.', 'Welcome, binational vision presentation, and meetings with strategic allies. Opening ceremony.', 'Bienvenue, présentation de la vision binationale et rencontres avec des alliés stratégiques. Cérémonie d''inauguration.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
