INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.serviciosMigratorios.desc', 'Facilitamos todos los trámites migratorios necesarios para que tu delegación comercial viaje a Toronto sin contratiempos. Nuestro equipo especializado te acompaña en cada paso, desde la solicitud hasta la aprobación.', 'We facilitate all the necessary immigration procedures so that your commercial delegation travels to Toronto without any setbacks. Our specialized team accompanies you every step of the way, from application to approval.', 'Nous facilitons toutes les procédures d''immigration nécessaires pour que votre délégation commerciale se rende à Toronto sans aucun revers. Notre équipe spécialisée vous accompagne à chaque étape, de la demande à l''approbation.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
