INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.serviciosMigratorios.service1.desc', 'Gestión completa para el trámite de visado, garantizando que tu delegación comercial cumpla con todos los requisitos para tu viaje de negocios a Toronto.', 'Complete management for the visa process, guaranteeing that your commercial delegation meets all the requirements for your business trip to Toronto.', 'Gestion complète du processus de visa, garantissant que votre délégation commerciale répond à toutes les exigences de votre voyage d''affaires à Toronto.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
