INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.ubicacion.title', 'Toronto, Canadá', 'Toronto, Canada', 'Toronto, Canada') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.ubicacion.titleEm', 'Te esperamos', 'We are waiting for you', 'Nous vous attendons') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.ubicacion.desc', 'En el corazón del centro financiero de Toronto, a pasos de los principales puntos de interés de la ciudad.', 'In the heart of Toronto''s financial center, steps from the city''s main points of interest.', 'Au cœur du centre financier de Toronto, à quelques pas des principaux points d''intérêt de la ville.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.ubicacion.cta', 'Ver en mapa', 'See on map', 'Voir sur la carte') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.ubicacion.details.llegar.title', 'Cómo llegar', 'How to get there', 'Comment y arriver') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.ubicacion.details.llegar.text', 'El recinto está ubicado en el corazón del centro de Toronto, a 5 minutos a pie de la estación Union Station. Fácil acceso desde el aeropuerto Pearson mediante UP Express (25 min) o taxi.', 'The venue is located in the heart of downtown Toronto, a 5-minute walk from Union Station. Easy access from Pearson Airport via UP Express (25 min) or taxi.', 'Le lieu est situé au cœur du centre-ville de Toronto, à 5 minutes à pied de la gare Union. Accès facile depuis l''aéroport Pearson via UP Express (25 min) ou taxi.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.ubicacion.details.recinto.title', 'El recinto', 'The enclosure', 'L''enceinte') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.ubicacion.details.recinto.text', 'Un espacio versátil con capacidad para más de 500 asistentes, salas de exposición, auditorio principal, áreas de networking y espacios para ruedas de negocio. Accesibilidad completa.', 'A versatile space with capacity for more than 500 attendees, exhibition rooms, main auditorium, networking areas and spaces for business conferences. Complete accessibility.', 'Un espace polyvalent d''une capacité de plus de 500 participants, des salles d''exposition, un auditorium principal, des zones de réseautage et des espaces pour les conférences d''affaires. Accessibilité totale.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.ubicacion.details.horarios.title', 'Horarios', 'Schedules', 'Horaires') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.ubicacion.details.horarios.text', 'El evento se llevará a cabo de <strong>9:00 a.m. a 7:00 p.m.</strong> todos los días. Registro abre a las 8:00 a.m. Sesiones de networking matutinas y eventos especiales por la tarde.', 'The event will take place from<strong>9:00 a.m. to 7:00 p.m.</strong>every day. Registration opens at 8:00 a.m. Morning networking sessions and special afternoon events.', 'L''événement aura lieu de<strong>9h00 à 19h00</strong>tous les jours. Les inscriptions ouvrent à 8h00. Séances de réseautage le matin et événements spéciaux l''après-midi.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.ubicacion.details.estacionamiento.title', 'Estacionamiento', 'Parking lot', 'Parking') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('home.ubicacion.details.estacionamiento.text', 'Estacionamiento público disponible en los alrededores del recinto. Tarifas desde $15 CAD por día. Recomendamos usar transporte público por la cercanía a Union Station.', 'Public parking available around the premises. Rates from $15 CAD per day. We recommend using public transportation due to the proximity to Union Station.', 'Parking public disponible autour des locaux. Tarifs à partir de 15$ CAD par jour. Nous vous recommandons d''utiliser les transports en commun en raison de la proximité de la gare Union.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('hero.visa.eyebrow', 'Expo México Mujer 2027', 'Expo Mexico Mujer 2027', 'Expo Mexique Femme 2027') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('hero.visa.title', 'Servicios Migratorios', 'Immigration Services', 'Services Migratoires') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('hero.visa.titleEm', 'Tu viaje a Canadá', 'Your journey to Canada', 'Votre voyage au Canada') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('hero.visa.desc', 'Te brindamos asesoría integral y gestoría especializada para tramitar tu visa de ingreso a Canadá. Nos encargamos de la revisión y acompañamiento de tu expediente para asegurar tu presencia en Toronto de manera rápida y sin complicaciones.', 'We provide comprehensive advice and specialized processing for your Canadian entry visa. We handle the review and follow-up of your application to ensure your presence in Toronto quickly and without complications.', 'Nous vous offrons des conseils complets et une gestion spécialisée pour traiter votre visa d''entrée au Canada. Nous nous occupons de la révision et du suivi de votre dossier pour assurer votre présence à Toronto rapidement et sans complications.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
