INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('hero.nosotros.desc', 'Una plataforma binacional que nace con la convicción de que el liderazgo mexicano femenino merece un escenario global. Cinco días en Toronto que transforman identidad en oportunidad.', 'A binational platform born from the conviction that Mexican women''s leadership deserves a global stage. Five days in Toronto that transform identity into opportunity.', 'Une plateforme binationale née de la conviction que le leadership des femmes mexicaines mérite une scène mondiale. Cinq jours à Toronto qui transforment l''identité en opportunité.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
