INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('hero.queEs.desc', 'Descubre nuestra misión, visión y los objetivos binacionales estratégicos que consolidan la alianza comercial y cultural entre México y Canadá.', 'Discover our mission, vision, and strategic binational objectives that consolidate the commercial and cultural alliance between Mexico and Canada.', 'Découvrez notre mission, vision et objectifs binationaux stratégiques qui consolident l''alliance commerciale et culturelle entre le Mexique et le Canada.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
