INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('hero.embajadoras.desc', 'Conoce a las embajadoras de Expo México Mujer. Mujeres excepcionales cuya trayectoria, liderazgo e influencia conectan fronteras y elevan el orgullo mexicano a nivel internacional.', 'Meet the ambassadors of Expo Mexico Mujer. Exceptional women whose careers, leadership, and influence connect borders and elevate Mexican pride internationally.', 'Rencontrez les ambassadrices de l''Expo Mexique Femme. Des femmes exceptionnelles dont le parcours, le leadership et l''influence connectent les frontières et élèvent la fierté mexicaine au niveau international.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
