INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('hero.participa.desc', 'Forma parte activa del encuentro empresarial y cultural más relevante entre México y Canadá. Stands comerciales, convocatorias estatales, patrocinios premium y ruedas de negocios.', 'Be an active part of the most relevant business and cultural encounter between Mexico and Canada. Commercial stands, state calls, premium sponsorships, and business roundtables.', 'Faites partie active de la rencontre commerciale et culturelle la plus pertinente entre le Mexique et le Canada. Stands commerciaux, appels d''offres étatiques, parrainages premium et tables rondes d''affaires.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
