INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('hero.summit.desc', 'El encuentro estratégico diseñado para consolidar acuerdos comerciales, fomentar inversiones mutuas y tender puentes operativos directos entre la delegación de empresarias mexicanas y los líderes corporativos de Ontario.', 'The strategic encounter designed to consolidate commercial agreements, foster mutual investments, and build direct operational bridges between the Mexican businesswomen delegation and Ontario''s corporate leaders.', 'La rencontre stratégique conçue pour consolider les accords commerciaux, encourager les investissements mutuels et établir des ponts opérationnels directs entre la délégation d''entrepreneures mexicaines et les dirigeants corporatifs de l''Ontario.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
