INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('hero.fashionshow.desc', 'Una noche excepcional donde la riqueza textil y artesanal de México converge con las pasarelas globales en Toronto, mostrando el talento de diseñadoras independientes a distribuidores y medios canadienses.', 'An exceptional night where Mexico''s textile and artisanal richness converges with global runways in Toronto, showcasing the talent of independent designers to Canadian distributors and media.', 'Une soirée exceptionnelle où la richesse textile et artisanale du Mexique converge avec les défilés mondiaux à Toronto, mettant en valeur le talent de créatrices indépendantes auprès de distributeurs et médias canadiens.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
