INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.bot.default', 'Bienvenida a Expo México Mujer 2027. ¿En qué podemos ayudarte a impulsar tu negocio hoy?', 'Welcome to Expo Mexico Mujer 2027. How can we help you grow your business today?', 'Bienvenue à l''Expo Mexique Femme 2027. Comment pouvons-nous vous aider à développer votre entreprise aujourd''hui?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.bot.expositores', 'Bienvenida a Expo México Mujer 2027. ¿Te interesa asegurar tu lugar como expositora y llegar a más clientes?', 'Welcome to Expo Mexico Mujer 2027. Are you interested in securing your spot as an exhibitor and reaching more clients?', 'Bienvenue à l''Expo Mexique Femme 2027. Souhaitez-vous sécuriser votre place en tant qu''exposante et toucher plus de clients?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.bot.embajadoras', 'Bienvenida al programa de Embajadoras EMM. ¿Lista para liderar y representar a tu estado?', 'Welcome to the EMM Ambassadors program. Ready to lead and represent your state?', 'Bienvenue dans le programme des Ambassadrices EMM. Prête à diriger et représenter votre état?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.bot.patrocinadores', 'Bienvenido a Expo México Mujer 2027. ¿Deseas potenciar tu marca con nuestros planes de patrocinio?', 'Welcome to Expo Mexico Mujer 2027. Would you like to boost your brand with our sponsorship plans?', 'Bienvenue à l''Expo Mexique Femme 2027. Souhaitez-vous renforcer votre marque avec nos plans de parrainage?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.bot.invitados', 'Bienvenido a Expo México Mujer 2027. ¿Tienes dudas sobre nuestros invitados especiales?', 'Welcome to Expo Mexico Mujer 2027. Do you have questions about our special guests?', 'Bienvenue à l''Expo Mexique Femme 2027. Avez-vous des questions sur nos invités spéciaux?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.bot.agenda', 'La Agenda EMM 2027 está llena de conferencias y networking. ¿Qué información buscas?', 'The EMM 2027 Agenda is packed with conferences and networking. What information are you looking for?', 'L''Agenda EMM 2027 est rempli de conférences et de réseautage. Quelle information recherchez-vous?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.bot.academy', 'Bienvenida a EMM Academy. ¿Lista para capacitarte y crecer tu negocio?', 'Welcome to EMM Academy. Ready to train and grow your business?', 'Bienvenue à l''EMM Academy. Prête à vous former et à développer votre entreprise?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.bot.visa', 'Sabemos que viajar a Canadá requiere preparación. ¿Tienes dudas sobre el trámite de tu eTA o Visa?', 'We know that traveling to Canada requires preparation. Do you have questions about your eTA or Visa process?', 'Nous savons que voyager au Canada nécessite une préparation. Avez-vous des questions sur votre processus de eTA ou de visa?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.bot.contacto', 'Estás en nuestra área de contacto. ¿Cómo podemos asistirte el día de hoy?', 'You''re in our contact area. How can we assist you today?', 'Vous êtes dans notre zone de contact. Comment pouvons-nous vous aider aujourd''hui?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.user.default', 'Hola, me gustaría obtener información sobre la Expo México Mujer 2027.', 'Hello, I would like to get information about Expo Mexico Mujer 2027.', 'Bonjour, j''aimerais obtenir des informations sur l''Expo Mexique Femme 2027.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.user.expositores', 'Hola, me gustaría recibir el dossier e información para participar como expositora.', 'Hello, I would like to receive the dossier and information to participate as an exhibitor.', 'Bonjour, j''aimerais recevoir le dossier et les informations pour participer en tant qu''exposante.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.user.embajadoras', 'Hola, me gustaría postularme o recibir más información sobre el programa de Embajadoras.', 'Hello, I would like to apply or get more information about the Ambassadors program.', 'Bonjour, j''aimerais postuler ou obtenir plus d''informations sur le programme des Ambassadrices.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.user.patrocinadores', 'Hola, me gustaría conocer las opciones comerciales y de patrocinio para el evento.', 'Hello, I would like to learn about the commercial and sponsorship options for the event.', 'Bonjour, j''aimerais connaître les options commerciales et de parrainage pour l''événement.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.user.invitados', 'Hola, me gustaría obtener más detalles sobre los invitados especiales de la Expo.', 'Hello, I would like to get more details about the special guests at the Expo.', 'Bonjour, j''aimerais obtenir plus de détails sur les invités spéciaux de l''Expo.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.user.agenda', 'Hola, me gustaría obtener más información sobre la agenda y el programa de actividades.', 'Hello, I would like to get more information about the agenda and activity program.', 'Bonjour, j''aimerais obtenir plus d''informations sur l''agenda et le programme d''activités.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.user.academy', 'Hola, me interesa conocer más sobre los talleres y capacitaciones de EMM Academy.', 'Hello, I''m interested in learning more about the workshops and training at EMM Academy.', 'Bonjour, je suis intéressée par les ateliers et formations de l''EMM Academy.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.user.visa', 'Hola, necesito asesoría sobre los trámites migratorios (Visa/eTA) para asistir a la Expo.', 'Hello, I need advice on immigration procedures (Visa/eTA) to attend the Expo.', 'Bonjour, j''ai besoin de conseils sur les procédures d''immigration (Visa/eTA) pour assister à l''Expo.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('wa.user.contacto', 'Hola, tengo una consulta general sobre la Expo México Mujer 2027.', 'Hello, I have a general inquiry about Expo Mexico Mujer 2027.', 'Bonjour, j''ai une demande générale concernant l''Expo Mexique Femme 2027.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
