INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.galeriaTitle', 'Kit de Prensa & Galería Multimedia', 'Press Kit & Multimedia Gallery', 'Dossier de presse et galerie multimédia') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.galeriaDesc', 'Ponemos a disposición de medios de comunicación, periodistas e instituciones el kit oficial de prensa que incluye logotipos en alta resolución, perfiles biográficos del equipo directivo y fotografías autorizadas del evento Ottawa 2026.', 'We make available to the media, journalists and institutions the official press kit that includes high-resolution logos, biographical profiles of the management team and authorized photographs of the Ottawa 2026 event.', 'Nous mettons à la disposition des médias, des journalistes et des institutions le dossier de presse officiel qui comprend des logos haute résolution, des profils biographiques de l''équipe de direction et des photographies autorisées de l''événement Ottawa 2026.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
