INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.mockPressReleases', '[{"date":"10 de Junio, 2026","title":"Expo México Mujer anuncia oficialmente su próxima sede en Toronto para el 2027","category":"Comunicado Oficial","desc":"Tras el contundente impacto de Ottawa, la directiva confirma la alianza con la Cámara de Comercio de Ontario para el montaje comercial de 2027."},{"date":"28 de Mayo, 2026","title":"Inauguración estelar de la Expo México Mujer en el Ottawa Convention Centre","category":"Comunicado de Prensa","desc":"Con presencia consular y delegadas empresariales de todo México, se inaugura formalmente el evento binacional más relevante del año."}]', '', '') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.mockInterviews', '[{"person":"Francisco Solorio","role":"Director General EMM","media":"Canadá Business Daily","quote":"La vinculación binacional es más que tratados; se trata de tender puentes directos y reales entre marcas mexicanas y canales de retail en Canadá."},{"person":"María López","role":"Fundadora de Mujeres en STEM","media":"Televisión Consular","quote":"Llevar software y talento tecnológico en manos de mexicanas a corporativos canadienses rompe paradigmas en la industria norteamericana."}]', '', '') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
