INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.press1Title', 'Expo México Mujer anuncia oficialmente su próxima sede en Toronto para el 2027', 'Expo México Mujer officially announces its next headquarters in Toronto for 2027', 'Expo México Mujer annonce officiellement son prochain siège social à Toronto pour 2027') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.press1Category', 'Comunicado Oficial', 'Official Statement', 'Déclaration officielle') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.press1Desc', 'Tras el contundente impacto de Ottawa, la directiva confirma la alianza con la Cámara de Comercio de Ontario para el montaje comercial de 2027.', 'After the overwhelming impact of Ottawa, the board confirms the alliance with the Ontario Chamber of Commerce for the 2027 trade assembly.', 'Après l''impact écrasant d''Ottawa, le conseil d''administration confirme l''alliance avec la Chambre de commerce de l''Ontario pour l''assemblée commerciale de 2027.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.press2Date', '15 de Mayo, 2026', 'May 15, 2026', '15 mai 2026') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.press2Title', 'Resultados históricos de vinculación B2B durante la jornada de clausura', 'Historical B2B engagement results during the closing day', 'Résultats historiques de l''engagement B2B au cours de la journée de clôture') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.press2Category', 'Reporte de Resultados', 'Results Report', 'Rapport de résultats') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.press2Desc', 'El pabellón de agroindustria superó las expectativas de exportación con más de 120 citas de negocio confirmadas y acuerdos comerciales por 2 MDD.', 'The agribusiness pavilion exceeded export expectations with more than 120 confirmed business appointments and commercial agreements worth 2 million dollars.', 'Le pavillon de l''agro-industrie a dépassé les attentes en matière d''exportation avec plus de 120 rendez-vous commerciaux confirmés et des accords commerciaux d''une valeur de 2 millions de dollars.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.interview1Person', 'Ana Sofía Garza', 'Ana Sofia Garza', 'Ana Sofia Garza') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.interview1Role', 'Directora Ejecutiva EMM', 'EMM Executive Director', 'Directeur Exécutif de l''EMM') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.interview1Media', 'Toronto Star', 'Toronto Star', 'Étoile de Toronto') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.interview1Quote', 'Nuestra visión no es solo exhibir productos, sino consolidar a la empresaria mexicana como un jugador clave en la cadena de suministro de Norteamérica.', 'Our vision is not only to showcase products, but to consolidate the Mexican businesswoman as a key player in the North American supply chain.', 'Notre vision n''est pas seulement de mettre en valeur les produits, mais de consolider la femme d''affaires mexicaine comme actrice clé de la chaîne d''approvisionnement nord-américaine.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.interview2Person', 'Elena Rodríguez', 'Elena Rodriguez', 'Elena Rodríguez') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.interview2Role', 'Expositora Destacada', 'Featured Exhibitor', 'Exposant en vedette') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.interview2Media', 'Financial Post', 'Financial Post', 'Poste financier') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.prensa.interview2Quote', 'La expo nos abrió las puertas de un mercado que creíamos inaccesible. Hoy nuestros textiles tienen distribución en tres provincias de Canadá.', 'The expo opened the doors to a market that we thought was inaccessible. Today our textiles are distributed in three provinces of Canada.', 'L’exposition nous a ouvert les portes d’un marché que l’on pensait inaccessible. Aujourd''hui nos textiles sont distribués dans trois provinces du Canada.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
