INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.viajero.vuelosDesc', 'Contamos con códigos promocionales oficiales de descuento en aerolíneas aliadas (Air Canada y Aeroméxico) aplicables para traslados directos hacia el Aeropuerto Internacional de Toronto Pearson (YYZ).', 'We have official discount promotional codes on allied airlines (Air Canada and Aeroméxico) applicable for direct transfers to Toronto Pearson International Airport (YYZ).', 'Nous avons des codes promotionnels de réduction officiels sur les compagnies aériennes alliées (Air Canada et Aeroméxico) applicables pour les transferts directs vers l''aéroport international Pearson de Toronto (YYZ).') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.viajero.vueloDesc1', 'Descuentos de hasta un 15% en vuelos de tarifa business y turista.', 'Discounts of up to 15% on business and tourist fare flights.', 'Réductions jusqu''à 15 % sur les vols à tarif affaires et touristiques.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.viajero.vueloDesc2', 'Soporte directo para la emisión de boletos grupales corporativos.', 'Direct support for corporate group ticketing.', 'Prise en charge directe de la billetterie de groupe d''entreprise.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
