INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.viajero.upExpressDesc', 'Conecta Pearson (YYZ) con Union Station en solo 25 minutos. Salidas cada 15 minutos.', 'Connects Pearson (YYZ) to Union Station in just 25 minutes. Departures every 15 minutes.', 'Relie Pearson (YYZ) à la gare Union en seulement 25 minutes. Départs toutes les 15 minutes.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
