INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.viajero.ttcDesc', 'Sistema de tránsito integrado de la ciudad que conecta de forma rápida hoteles con todas las sedes.', 'Integrated city transit system that quickly connects hotels to all venues.', 'Système de transport en commun intégré qui relie rapidement les hôtels à tous les sites.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
