INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.viajero.hotel1Desc', 'Hotel sede oficial ubicado a pasos del lago Ontario. Cuenta con tarifas preferenciales exclusivas para expositoras de la delegación de EMM.', 'Official headquarters hotel located steps from Lake Ontario. It has exclusive preferential rates for exhibitors from the EMM delegation.', 'Hôtel du siège officiel situé à quelques pas du lac Ontario. Il bénéficie de tarifs préférentiels exclusifs pour les exposants de la délégation EMM.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
