INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.viajero.hotel2Name', 'Sheraton Centre Toronto', 'Sheraton Center Toronto', 'Sheraton Centre Toronto') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
