INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.viajero.hotel2Desc', 'Ubicación céntrica en el corazón financiero de Toronto. Conexión directa al PATH y fácil acceso en transporte público a las sedes del evento.', 'Central location in the financial heart of Toronto. Direct connection to the PATH and easy access by public transportation to the event venues.', 'Emplacement central dans le cœur financier de Toronto. Connexion directe au PATH et accès facile en transports en commun aux lieux de l''événement.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.viajero.hotel2Rate', 'Desde $195 CAD / noche', 'From $195 CAD / night', 'À partir de 195$ CAD / nuit') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.srOnly', 'Participantes', 'Participants', 'Participants') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.manualTitle', 'Manual Técnico del Expositor', 'Exhibitor''s Technical Manual', 'Manuel technique de l''exposant') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.manualDesc', 'Accede al documento oficial que contiene toda la normativa y logística técnica para el montaje en la sede de Toronto. Incluye horarios de carga y descarga, especificaciones eléctricas, dimensiones de los stands y reglamentos de seguridad.', 'Access the official document that contains all the regulations and technical logistics for the assembly at the Toronto headquarters. Includes loading and unloading schedules, electrical specifications, stand dimensions and safety regulations.', 'Accédez au document officiel qui contient tous les règlements et la logistique technique du montage au siège de Toronto. Comprend les horaires de chargement et de déchargement, les spécifications électriques, les dimensions du stand et les règles de sécurité.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.descargarManual', 'Descargar Manual (PDF)', 'Download Manual (PDF)', 'Télécharger le manuel (PDF)') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.especificacionesTitle', 'Especificaciones de Stands', 'Stand Specifications', 'Spécifications du support') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.standStandard', 'Stand Standard: 3m x 2m con panel divisor y rotulación frontal.', 'Standard Stand: 3m x 2m with divider panel and front lettering.', 'Stand standard : 3 mx 2 m avec panneau de séparation et lettrage frontal.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.mobiliarioIncluido', 'Mobiliario Incluido: 1 mesa con mantel, 2 sillas y conexión eléctrica.', 'Furniture Included: 1 table with tablecloth, 2 chairs and electrical connection.', 'Mobilier Inclus : 1 table avec nappe, 2 chaises et branchement électrique.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.serviciosAdicionales', 'Servicios Adicionales: Internet de alta velocidad y almacén compartido.', 'Additional Services: High-speed Internet and shared warehouse.', 'Services additionnels : Internet haute vitesse et entrepôt partagé.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.requisitosTitle', 'Requisitos de Participación', 'Participation Requirements', 'Conditions de participation') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.docComercialTitle', 'Documentación Comercial', 'Commercial Documentation', 'Documents commerciaux') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.docComercialDesc', 'Contar con registro fiscal (RFC), marca registrada y ficha técnica de exportación de los productos a exhibir en la sede.', 'Have tax registration (RFC), registered trademark and technical export sheet for the products to be exhibited at the headquarters.', 'Disposer d''un enregistrement fiscal (RFC), d''une marque déposée et d''une fiche technique d''exportation des produits à exposer au siège.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.estatusMigratorioTitle', 'Estatus Migratorio', 'Immigration Status', 'Statut d''immigration') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.estatusMigratorioDesc', 'Pasaporte con vigencia mínima de 6 meses y visa canadiense / eTA autorizada. EMM ofrece cartas oficiales de invitación para expositoras registradas.', 'Passport valid for at least 6 months and authorized Canadian visa/eTA. EMM offers official invitation letters for registered exhibitors.', 'Passeport valide pour au moins 6 mois et visa canadien/AVE autorisé. EMM propose des lettres d''invitation officielles aux exposants inscrits.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.certSanitariaTitle', 'Certificación Sanitaria', 'Health Certification', 'Certificat de santé') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.certSanitariaDesc', 'En el sector de alimentos o salud y cosmética, se requiere cumplir con las directivas de etiquetado y sanidad de Health Canada.', 'In the food or health and cosmetics sector, compliance with Health Canada''s labeling and sanitation directives is required.', 'Dans le secteur alimentaire ou celui de la santé et des cosmétiques, le respect des directives d''étiquetage et d''hygiène de Santé Canada est requis.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.faqTitle', 'Preguntas Frecuentes', 'Frequently Asked Questions', 'Foire aux questions') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.faq1Q', '¿El costo del stand incluye traslado de mercancía?', 'Does the cost of the stand include transportation of merchandise?', 'Le coût du stand comprend-il le transport des marchandises ?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.faq1A', 'No, el costo del stand cubre únicamente el espacio de exhibición y el mobiliario básico. La transportación aduanal corre por cuenta de cada expositora, sin embargo, el equipo logístico de EMM brinda tarifas consolidadas preferentes con nuestro socio transportista oficial.', 'No, the cost of the stand covers only the exhibition space and basic furniture. Customs transportation is the responsibility of each exhibitor, however, the EMM logistics team provides preferential consolidated rates with our official transport partner.', 'Non, le prix du stand couvre uniquement l''espace d''exposition et le mobilier de base. Le transport sous douane est à la charge de chaque exposant, cependant, l''équipe logistique d''EMM propose des tarifs préférentiels consolidés auprès de notre partenaire transport officiel.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.faq2Q', '¿Cómo puedo obtener una carta de invitación para mi visa?', 'How can I get an invitation letter for my visa?', 'Comment puis-je obtenir une lettre d''invitation pour mon visa ?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.faq2A', 'Una vez realizado el depósito de confirmación de tu stand, el comité organizador expedirá una carta oficial membretada que incluye los detalles del evento, avalada para presentarse ante el consulado canadiense correspondiente.', 'Once the confirmation deposit for your stand has been made, the organizing committee will issue an official letter on letterhead that includes the details of the event, certified to be presented to the corresponding Canadian consulate.', 'Une fois le dépôt de confirmation de votre stand effectué, le comité organisateur émettra une lettre officielle sur papier à en-tête comprenant les détails de l''événement, certifiée pour être présentée au consulat canadien correspondant.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.faq3Q', '¿Qué sucede si mis productos requieren refrigeración?', 'What happens if my products require refrigeration?', 'Que se passe-t-il si mes produits nécessitent une réfrigération ?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participantes.faq3A', 'Debes notificarlo con al menos 60 días de anticipación al correo de logística (luis.garcia@expomexico.ca) para cotizar el suministro eléctrico dedicado y el arrendamiento de vitrinas o congeladores en la sede.', 'You must notify at least 60 days in advance to the logistics email (luis.garcia@expomexico.ca) to quote the dedicated electricity supply and the rental of display cases or freezers at the headquarters.', 'Vous devez prévenir au moins 60 jours à l''avance au courriel logistique (luis.garcia@expomexico.ca) pour citer la fourniture d''électricité dédiée et la location de vitrines ou de congélateurs au siège.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.srOnly', 'Logística', 'Logistics', 'Logistique') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.esquemasTitle', 'Esquemas de Exportación', 'Export Schemes', 'Programmes d''exportation') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.esquemasDesc', 'Para el ingreso de tus productos de exhibición a territorio canadiense, el comité organizador de Expo México Mujer ofrece asesoría y acompañamiento técnico en dos esquemas comerciales principales.', 'For the entry of your exhibition products into Canadian territory, the organizing committee of Expo México Mujer offers advice and technical support in two main commercial schemes.', 'Pour l''entrée de vos produits d''exposition sur le territoire canadien, le comité organisateur d''Expo México Mujer vous offre conseils et soutien technique dans deux principaux schémas commerciaux.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.importante', 'Importante:', 'Important:', 'Important:') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.importanteDesc', 'Los trámites aduanales deben iniciarse al menos con 90 días de anticipación para evitar demoras en aduana fronteriza.', 'Customs procedures must be started at least 90 days in advance to avoid delays at border customs.', 'Les procédures douanières doivent être entamées au moins 90 jours à l''avance pour éviter les retards aux douanes frontalières.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.expTemporalTitle', 'Exportación Temporal', 'Temporary Export', 'Exportation temporaire') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.expTemporalDesc', 'Ideal para muestras de exhibición, mobiliario de stand o piezas de pasarela que regresarán a México después del evento. Exento del pago de aranceles bajo el cuaderno ATA o fianza aduanal temporal.', 'Ideal for display samples, booth furniture or runway pieces that will return to Mexico after the event. Exempt from paying tariffs under the ATA carnet or temporary customs bond.', 'Idéal pour exposer des échantillons, des meubles de stand ou des pièces de défilé qui reviendront au Mexique après l''événement. Exonéré du paiement des droits de douane au titre du carnet ATA ou de la caution douanière temporaire.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.expDefinitivaTitle', 'Exportación Definitiva', 'Definitive Export', 'Exportation définitive') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.expDefinitivaDesc', 'Recomendado para productos destinados a la venta directa en el evento, muestras de degustación consumibles o inventario vendido previamente a importadores canadienses. Sujeto a impuestos e importación formal canadiense.', 'Recommended for products intended for direct sale at the event, consumable tasting samples, or inventory previously sold to Canadian importers. Subject to tax and formal Canadian import.', 'Recommandé pour les produits destinés à la vente directe lors de l''événement, les échantillons de dégustation consommables ou les stocks précédemment vendus à des importateurs canadiens. Soumis aux taxes et à l''importation formelle au Canada.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.asesoriaTitle', 'Asesoría & Soluciones de Transporte', 'Transportation Consulting & Solutions', 'Conseils et solutions en matière de transport') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.consolidacionTitle', 'Consolidación de Carga', 'Cargo Consolidation', 'Consolidation du fret') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.consolidacionDesc', 'Ofrecemos recolección de mercancías en hubs estratégicos (CDMX, Guadalajara y Monterrey) para realizar un embarque consolidated terrestre o aéreo hacia Toronto con tarifas preferenciales.', 'We offer collection of merchandise in strategic hubs (CDMX, Guadalajara and Monterrey) to carry out a consolidated shipment by land or air to Toronto with preferential rates.', 'Nous proposons la collecte de marchandises dans des hubs stratégiques (CDMX, Guadalajara et Monterrey) pour effectuer un envoi groupé par voie terrestre ou aérienne vers Toronto avec des tarifs préférentiels.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.brokerageTitle', 'Brokerage Aduanal', 'Customs Brokerage', 'Courtage en douane') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.brokerageDesc', 'Coordinación integral con agencias aduanales en frontera (Laredo) y en las aduanas de Canadá para agilizar la clasificación arancelaria y la liberación de embarques comerciales.', 'Comprehensive coordination with customs agencies at the border (Laredo) and at Canadian customs to expedite the tariff classification and release of commercial shipments.', 'Coordination complète avec les agences douanières à la frontière (Laredo) et aux douanes canadiennes pour accélérer le classement tarifaire et la mainlevée des expéditions commerciales.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.entregaTitle', 'Servicio de Entrega Final', 'Final Delivery Service', 'Service de livraison finale') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.logistica.entregaDesc', 'Recepción de mercancía en el warehouse de Toronto previo al evento, custodia asegurada y entrega directa de cajas en el stand asignado a cada delegada expositora.', 'Reception of merchandise in the Toronto warehouse prior to the event, secured custody and direct delivery of boxes to the stand assigned to each exhibiting delegate.', 'Réception de la marchandise à l''entrepôt de Toronto avant l''événement, garde sécurisée et livraison directe des cartons au stand attribué à chaque délégué exposant.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
