INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expositores.descubreTalentoDesc', 'Explora las marcas, productos y servicios que las mujeres emprendedoras de México traen a Toronto. Haz clic en una categoría para ver su directorio.', 'Explore the brands, products and services that women entrepreneurs from Mexico bring to Toronto. Click on a category to see its directory.', 'Découvrez les marques, produits et services que les femmes entrepreneures du Mexique apportent à Toronto. Cliquez sur une catégorie pour voir son répertoire.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
