INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expositores.standsYEspacios', 'Stands y Espacios de Exhibición', 'Stands and Exhibition Spaces', 'Stands et espaces d''exposition') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expositores.standsDesc', 'Diseñamos cada espacio para proyectar la máxima presencia corporativa. Nuestros stands de 3x3 y 2x2 metros están completamente equipados con rotulación oficial de la marca, iluminación LED direccional y conexiones eléctricas de 110v listas para usar en el centro de convenciones de Toronto.', 'We design each space to project the maximum corporate presence. Our 3x3 and 2x2 meter booths are fully equipped with official brand signage, directional LED lighting and 110v electrical connections ready to use at the Toronto Convention Centre.', 'Nous concevons chaque espace pour projeter la présence maximale de l''entreprise. Nos stands de 3x3 et 2x2 mètres sont entièrement équipés d''une signalisation officielle de la marque, d''un éclairage LED directionnel et de connexions électriques 110 V prêtes à l''emploi au Centre des congrès de Toronto.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
