INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.embajadoras.busquedaDesc', 'Buscamos líderes empresariales, gestoras culturales y emprendedoras con visión global en cada estado de la República Mexicana para ser las portavoces del talento de sus regiones en Toronto, Canadá.', 'We are looking for business leaders, cultural managers and entrepreneurs with a global vision in each state of the Mexican Republic to be spokespersons for the talent of their regions in Toronto, Canada.', 'Nous recherchons des chefs d''entreprise, des gestionnaires culturels et des entrepreneurs ayant une vision globale dans chaque État de la République mexicaine pour être les porte-parole du talent de leurs régions à Toronto, Canada.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
