INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.embajadoras.conoceEmbajadoras', 'Conoce a nuestras Embajadoras de México', 'Meet our Mexican Ambassadors', 'Rencontrez nos ambassadeurs mexicains') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.embajadoras.conoceEmbajadorasDesc', 'Las Embajadoras de Expo México Mujer son líderes comprometidas con el desarrollo económico y social de sus comunidades. Selecciona un estado para conocerlas.', 'The Expo México Mujer Ambassadors are leaders committed to the economic and social development of their communities. Select a state to see them.', 'Les ambassadeurs d''Expo México Mujer sont des leaders engagés dans le développement économique et social de leurs communautés. Sélectionnez un état pour les voir.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
