INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.embajadoras.registroEmbajadoras', 'Registro Oficial de Embajadoras', 'Official Registry of Ambassadors', 'Registre officiel des ambassadeurs') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.embajadoras.registroEmbajadorasDesc', 'Completa el formulario de postulación oficial para solicitar ser la embajadora representante de tu estado en Expo México Mujer Toronto.', 'Complete the official application form to request to be the ambassador representing your state at Expo México Mujer Toronto.', 'Remplissez le formulaire de candidature officiel pour demander à devenir ambassadeur représentant votre État à Expo México Mujer Toronto.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.compradores.vinculacionB2B', 'Vinculación Comercial B2B', 'B2B Commercial Linkage', 'Lien commercial B2B') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.compradores.compradoresTitle', 'Compradores e Inversionistas', 'Buyers and Investors', 'Acheteurs et investisseurs') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.compradores.compradoresDesc', 'El puente directo para importadores, distribuidores y compradores corporativos en Canadá interesados en adquirir productos mexicanos de la más alta calidad y establecer alianzas de inversión.', 'The direct bridge for importers, distributors and corporate buyers in Canada interested in acquiring Mexican products of the highest quality and establishing investment alliances.', 'Le pont direct pour les importateurs, les distributeurs et les acheteurs corporatifs au Canada intéressés à acquérir des produits mexicains de la plus haute qualité et à établir des alliances d''investissement.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.compradores.ruedaNegocios', 'Rueda de Negocios Vinculación Efectiva', '{"title":"Business Roundtables","title2":"Effective Linkage","desc":"Through our linkage program, we organize customized B2B agendas. Canadian buyers can pre-select exhibitors based on their industry, export capacity, and certifications, optimizing meetings in Toronto to the fullest.","perfilamiento":{"title":"Smart Profiling","desc":"We filter proposals from businesswomen to ensure alignment with your purchasing lines."},"agenda":{"title":"Strategic Agenda","desc":"Structured one-on-one meetings of 20 minutes scheduled weeks before the event."},"proyeccion":{"title":"International Reach","desc":"We facilitate sample shipping logistics and follow-up commercial support."},"ruedaLabel":"Business Roundtables","ontarioSummit":"Ontario Business Summit 2027"}', 'Liens efficaces entre les tables rondes d’affaires') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.compradores.ruedaDesc', 'A través del programa de vinculación, organizamos agendas personalizadas B2B. Los compradores canadienses pueden pre-seleccionar a las expositoras según su industria, capacidad exportadora y certificaciones, optimizando al máximo los encuentros en Toronto.', 'Through the linking program, we organize personalized B2B agendas. Canadian buyers can pre-select exhibitors based on their industry, export capacity and certifications, optimizing meetings in Toronto to the maximum.', 'Grâce au programme de liaison, nous organisons des agendas B2B personnalisés. Les acheteurs canadiens peuvent présélectionner les exposants en fonction de leur secteur d''activité, de leur capacité d''exportation et de leurs certifications, optimisant ainsi au maximum les réunions à Toronto.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.compradores.perfilamiento', 'Perfilamiento Inteligente', 'Smart Profiling', 'Profilage intelligent') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.compradores.perfilamientoDesc', 'Filtramos las propuestas de las empresarias para asegurar el encaje con sus líneas de compra.', 'We filter the businesswomen''s proposals to ensure they fit with their purchasing lines.', 'Nous filtrons les propositions des femmes d''affaires pour nous assurer qu''elles correspondent à leurs lignes d''achat.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.compradores.agendaEstrategica', 'Agenda Estratégica', 'Strategic Agenda', 'Programme stratégique') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.compradores.agendaEstrategicaDesc', 'Citas estructuradas uno a uno de 20 minutos programadas semanas antes del evento.', 'Structured one-on-one 20-minute appointments scheduled weeks before the event.', 'Rendez-vous individuels structurés de 20 minutes prévus des semaines avant l''événement.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
