INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.beneficiosPartDesc', 'Posiciona tu negocio a nivel internacional e interactúa directamente con importadores, distribuidores y el público general canadiense.', 'Position your business internationally and interact directly with importers, distributors and the general Canadian public.', 'Positionnez votre entreprise à l''international et interagissez directement avec les importateurs, les distributeurs et le grand public canadien.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
