INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.categoriasPatrocinio', 'Categorías de Patrocinio', 'Sponsorship Categories', 'Catégories de parrainage') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.categoriasPatrocinioDesc', 'Ofrecemos distintas modalidades de vinculación comercial para adaptarnos al tamaño e impacto de tu corporación: Platino, Oro, Plata y Bronce, además de patrocinios especiales en áreas temáticas específicas como gastronomía, moda o tecnología.', 'We offer different types of commercial links to adapt to the size and impact of your corporation: Platinum, Gold, Silver and Bronze, as well as special sponsorships in specific thematic areas such as gastronomy, fashion or technology.', 'Nous proposons différents types de liens commerciaux pour nous adapter à la taille et à l''impact de votre entreprise : Platine, Or, Argent et Bronze, ainsi que des parrainages spéciaux dans des domaines thématiques spécifiques comme la gastronomie, la mode ou la technologie.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.beneficiosPatrocinio', 'Beneficios de Patrocinio', 'Sponsorship Benefits', 'Avantages du parrainage') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.beneficiosPatrocinioDesc', 'Los patrocinadores oficiales reciben una exposición de marca inigualable en todas las plataformas digitales, físicas, impresas y espacios VIP del evento, sumado a oportunidades directas de vinculación con delegaciones empresariales de alto nivel.', 'Official sponsors receive unparalleled brand exposure across all digital, physical, print and VIP event platforms, plus direct networking opportunities with high-level business delegations.', 'Les sponsors officiels bénéficient d''une visibilité de marque inégalée sur toutes les plateformes d''événements numériques, physiques, imprimés et VIP, ainsi que d''opportunités de réseautage direct avec des délégations commerciales de haut niveau.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.liderazgoTerritorial', 'Liderazgo Territorial', 'Territorial Leadership', 'Leadership territorial') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.embajadorasEMM', 'Embajadoras Expo México Mujer', 'Expo México Women Ambassadors', 'Femmes ambassadrices d’Expo México') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.convocatoriaNacional', 'Convocatoria Nacional', 'National Call', 'Appel national') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.convocatoriaNacionalDesc', 'Buscamos a mujeres líderes en cada rincón del país que deseen representar los valores de innovación, cultura y esfuerzo de la mujer mexicana en Canadá.', 'We are looking for women leaders in every corner of the country who wish to represent the values ​​of innovation, culture and effort of Mexican women in Canada.', 'Nous recherchons des femmes leaders aux quatre coins du pays qui souhaitent représenter les valeurs d''innovation, de culture et d''effort des femmes mexicaines au Canada.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.representacionEstatal', 'Representación Estatal', 'State Representation', 'Représentation de l''État') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.representacionEstatalDesc', 'Las embajadoras coordinan la participación territorial de sus estados, llevando muestras artesanales, gastronómicas e industriales representativas del interior de la república.', 'The ambassadors coordinate the territorial participation of their states, bringing artisanal, gastronomic and industrial samples representative of the interior of the republic.', 'Les ambassadeurs coordonnent la participation territoriale de leurs États, apportant des échantillons artisanaux, gastronomiques et industriels représentatifs de l''intérieur de la république.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.registroAspirantes', 'Registro de Aspirantes', 'Applicant Registration', 'Inscription des candidats') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.registroAspirantesDesc', 'Si deseas postularte o proponer a una líder de tu comunidad, completa nuestro formulario oficial para ser evaluada por el comité directivo.', 'If you wish to apply or propose a leader from your community, complete our official form to be evaluated by the steering committee.', 'Si vous souhaitez postuler ou proposer un leader de votre communauté, remplissez notre formulaire officiel pour être évalué par le comité directeur.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
