INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.aliadosEstrategicosDesc', 'Empresas y agencias de desarrollo que co-crean valor y sustentan la estructura del evento.', 'Companies and development agencies that co-create value and support the structure of the event.', 'Entreprises et agences de développement qui co-créent de la valeur et soutiennent la structure de l''événement.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
