INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.camarasDesc', 'Cámaras binacionales y asociaciones de comercio que promueven los intercambios comerciales.', 'Binational chambers and trade associations that promote commercial exchanges.', 'Chambres binationales et associations professionnelles qui favorisent les échanges commerciaux.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.ponentesLideres', 'Ponentes y Líderes', 'Speakers and Leaders', 'Conférenciers et dirigeants') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.invitadosTitle', 'Invitados Especiales', 'Special Guests', 'Invités spéciaux') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.invitadosDesc', 'Nuestra agenda se nutre con la experiencia de líderes empresariales sobresalientes, conferencistas inspiradoras y personalidades influyentes en el ámbito del comercio internacional y el empoderamiento femenino de Canadá y Latinoamérica.', 'Our agenda is nourished by the experience of outstanding business leaders, inspiring speakers and influential personalities in the field of international trade and female empowerment from Canada and Latin America.', 'Notre programme est nourri par l’expérience de chefs d’entreprise exceptionnels, de conférenciers inspirants et de personnalités influentes dans le domaine du commerce international et de l’autonomisation des femmes du Canada et d’Amérique latine.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.vinculacionB2BInv', 'Vinculación B2B', 'B2B Linking', 'Liens B2B') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.compradoresTitleInv', 'Compradores e Inversionistas', 'Buyers and Investors', 'Acheteurs et investisseurs') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.compradoresDescInv', 'Si eres distribuidor, comprador corporativo o inversionista en Canadá y deseas contactar con productos premium mexicanos, este es tu espacio de vinculación.', 'If you are a distributor, corporate buyer or investor in Canada and want to contact premium Mexican products, this is your networking space.', 'Si vous êtes un distributeur, un acheteur corporatif ou un investisseur au Canada et que vous souhaitez contacter des produits mexicains haut de gamme, ceci est votre espace de réseautage.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.registroCompradoresInv', 'Registro de Compradores', 'Buyer Registration', 'Inscription de l''acheteur') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.registroCompradoresDescInv', 'Obtén credenciales VIP y accede a las agendas exclusivas de citas de negocios uno a uno durante el evento.', 'Earn VIP credentials and access exclusive one-on-one business appointment schedules during the event.', 'Gagnez des informations d''identification VIP et accédez à des horaires de rendez-vous professionnels individuels exclusifs pendant l''événement.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
