INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.directorioCompradoresDescInv', 'Directorio dinámico que facilita a las marcas identificar y conectar con perfiles de interés comercial.', 'Dynamic directory that makes it easier for brands to identify and connect with profiles of commercial interest.', 'Annuaire dynamique qui permet aux marques d''identifier plus facilement et de se connecter avec des profils d''intérêt commercial.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
