INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.vinculacionEmpresarialDescInv', 'Mesas redondas de negociación sectoriales guiadas por mentores comerciales certificados.', 'Sector negotiation round tables guided by certified business mentors.', 'Tables rondes de négociation sectorielle guidées par des mentors d''affaires certifiés.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
