INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.aliados.card2Desc', 'Gobiernos estatales, embajadas y consulados de ambos países respaldando las operaciones.', 'State governments, embassies and consulates of both countries supporting the operations.', 'Les gouvernements des États, les ambassades et les consulats des deux pays soutiennent les opérations.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
