INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.aliados.card3Desc', 'Cámaras binacionales y asociaciones de comercio que promueven los intercambios comerciales.', 'Binational chambers and trade associations that promote commercial exchanges.', 'Chambres binationales et associations professionnelles qui favorisent les échanges commerciaux.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.invitados.eyebrow', 'Ponentes y Líderes', 'Speakers and Leaders', 'Conférenciers et dirigeants') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.invitados.title', 'Invitados Especiales', 'Special Guests', 'Invités spéciaux') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.invitados.desc', 'Nuestra agenda se nutre con la experiencia de líderes empresariales sobresalientes, conferencistas inspiradoras y personalidades influyentes en el ámbito del comercio internacional y el empoderamiento femenino de Canadá y Latinoamérica.', 'Our agenda is nourished by the experience of outstanding business leaders, inspiring speakers and influential personalities in the field of international trade and female empowerment from Canada and Latin America.', 'Notre programme est nourri par l’expérience de chefs d’entreprise exceptionnels, de conférenciers inspirants et de personnalités influentes dans le domaine du commerce international et de l’autonomisation des femmes du Canada et d’Amérique latine.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.compradores.eyebrow', 'Vinculación B2B', 'B2B Linking', 'Liens B2B') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.compradores.title', 'Compradores e Inversionistas', 'Buyers and Investors', 'Acheteurs et investisseurs') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.compradores.desc', 'Si eres distribuidor, comprador corporativo o inversionista en Canadá y deseas contactar con productos premium mexicanos, este es tu espacio de vinculación.', 'If you are a distributor, corporate buyer or investor in Canada and want to contact premium Mexican products, this is your networking space.', 'Si vous êtes un distributeur, un acheteur corporatif ou un investisseur au Canada et que vous souhaitez contacter des produits mexicains haut de gamme, ceci est votre espace de réseautage.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.compradores.card1Title', 'Registro de Compradores', 'Buyer Registration', 'Inscription de l''acheteur') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.compradores.card1Desc', 'Obtén credenciales VIP y accede a las agendas exclusivas de citas de negocios uno a uno durante el evento.', 'Earn VIP credentials and access exclusive one-on-one business appointment schedules during the event.', 'Gagnez des informations d''identification VIP et accédez à des horaires de rendez-vous professionnels individuels exclusifs pendant l''événement.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.compradores.card2Title', 'Directorio de Compradores', 'Buyers Directory', 'Annuaire des acheteurs') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.compradores.card2Desc', 'Directorio dinámico que facilita a las marcas identificar y conectar con perfiles de interés comercial.', 'Dynamic directory that makes it easier for brands to identify and connect with profiles of commercial interest.', 'Annuaire dynamique qui permet aux marques d''identifier plus facilement et de se connecter avec des profils d''intérêt commercial.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.compradores.card3Title', 'Vinculación Empresarial', 'Business Linkage', 'Lien commercial') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.participa.compradores.card3Desc', 'Mesas redondas de negociación sectoriales guiadas por mentores comerciales certificados.', 'Sector negotiation round tables guided by certified business mentors.', 'Tables rondes de négociation sectorielle guidées par des mentors d''affaires certifiés.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
