INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.aliados.aliadosTitle', 'Aliados Estratégicos & Cámaras', 'Strategic Allies & Chambers', 'Alliés et chambres stratégiques') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.aliados.aliadosDesc', 'Expo México Mujer cuenta con el respaldo y vinculación activa de organismos gubernamentales, cámaras de comercio binacionales y asociaciones empresariales comprometidas con la integración económica y el liderazgo femenino.', 'Expo México Mujer has the support and active involvement of government agencies, binational chambers of commerce and business associations committed to economic integration and female leadership.', 'Expo México Mujer bénéficie du soutien et de la participation active d''agences gouvernementales, de chambres de commerce binationales et d''associations professionnelles engagées dans l''intégration économique et le leadership féminin.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.aliados.aliadosEstTitle', 'Aliados Estratégicos', 'Strategic Allies', 'Alliés stratégiques') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.aliados.aliadosEstDesc', 'Empresas líderes del sector privado nacional e internacional que aportan innovación, recursos y soporte operativo clave para materializar la visión binacional del evento.', 'Leading companies from the national and international private sector that provide innovation, resources and key operational support to materialize the binational vision of the event.', 'Des entreprises leaders du secteur privé national et international qui fournissent de l''innovation, des ressources et un soutien opérationnel clé pour matérialiser la vision binationale de l''événement.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
