INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.aliados.aliadosInstDesc', 'Entidades gubernamentales, consulados y embajadas de México y Canadá que brindan respaldo oficial, legitimidad y acompañamiento político en todos los intercambios.', 'Government entities, consulates and embassies of Mexico and Canada that provide official support, legitimacy and political accompaniment in all exchanges.', 'Entités gouvernementales, consulats et ambassades du Mexique et du Canada qui fournissent un soutien officiel, une légitimité et un accompagnement politique dans tous les échanges.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
