INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.aliados.camarasEmpDesc', 'Organizaciones e intermediarios de negocios (como COMCE, cámaras hispanas y asociaciones locales de Ontario) que catalizan las ruedas de negocios y el networking comercial.', 'Organizations and business intermediaries (such as COMCE, Hispanic chambers and local associations in Ontario) that catalyze business roundtables and commercial networking.', 'Organisations et intermédiaires commerciaux (comme le COMCE, les chambres hispaniques et les associations locales de l''Ontario) qui catalysent les tables rondes d''affaires et le réseautage commercial.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
