INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.missionVisionTitle', 'México en el mundo, con todo su poder', 'Mexico in the world, with all its power', 'Le Mexique dans le monde, avec toute sa puissance') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.misionLabel', 'Misión', 'Mission', 'Mission') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.misionTitle', 'Conectar el talento mexicano con el mundo', 'Connect Mexican talent with the world', 'Connectez les talents mexicains au monde') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.misionText', 'Consolidar la proyección internacional de México a través de una plataforma que conecta el talento, la cultura y los productos mexicanos con oportunidades concretas en Canadá, impulsando el desarrollo económico y fortaleciendo la identidad nacional en el extranjero.', 'Consolidate the international projection of Mexico through a platform that connects Mexican talent, culture and products with specific opportunities in Canada, promoting economic development and strengthening national identity abroad.', 'Consolider la projection internationale du Mexique grâce à une plateforme qui relie les talents, la culture et les produits mexicains à des opportunités spécifiques au Canada, favorisant le développement économique et renforçant l''identité nationale à l''étranger.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.visionLabel', 'Visión', 'Vision', 'Vision') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.visionTitle', 'Ser el referente binacional del liderazgo femenino', 'To be the binational reference for female leadership', 'Être la référence binationale du leadership féminin') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.visionText', 'Ser el referente binacional más importante para el liderazgo femenino mexicano, creando un ecosistema de negocios, cultura y comunidad que trascienda generaciones y fronteras.', 'To be the most important binational reference for Mexican female leadership, creating an ecosystem of business, culture and community that transcends generations and borders.', 'Être la référence binationale la plus importante en matière de leadership féminin mexicain, en créant un écosystème d''affaires, de culture et de communauté qui transcende les générations et les frontières.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.statsLocation', 'Toronto · Canadá', 'Toronto Canada', 'Toronto Canada') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.statsHeadline', 'El liderazgo mexicano no tiene fronteras', 'Mexican leadership has no borders', 'Le leadership mexicain n’a pas de frontières') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
