INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.statsAsistentesDesc', 'Mujeres líderes, ejecutivas y emprendedoras de alto impacto.', 'High-impact women leaders, executives and entrepreneurs.', 'Femmes leaders, cadres et entrepreneures à fort impact.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.statsConferenciasLabel', 'Conferencias Magistrales', 'Master Conferences', 'Conférences de maître') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.statsConferenciasDesc', 'Voces internacionales que inspiran y transforman industrias.', 'International voices that inspire and transform industries.', 'Des voix internationales qui inspirent et transforment les industries.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
