INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.statsNetworkingDesc', 'Mesas de negocios para cerrar alianzas comerciales binacionales.', 'Business tables to close binational commercial alliances.', 'Des tables d’affaires pour conclure des alliances commerciales binationales.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.statsTalentoLabel', 'Talento Mexicano', 'Mexican Talent', 'Talent mexicain') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.statsTalentoDesc', 'Proyección global de nuestra cultura, innovación y excelencia.', 'Global projection of our culture, innovation and excellence.', 'Projection mondiale de notre culture, de notre innovation et de notre excellence.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.valsTitle', 'Lo que nos define, nos distingue', 'What defines us, distinguishes us', 'Ce qui nous définit, nous distingue') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.valsDesc', 'Cuatro valores que guían cada decisión, cada alianza y cada paso.', 'Four values ​​that guide every decision, every alliance and every step.', 'Quatre valeurs qui guident chaque décision, chaque alliance et chaque étape.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.val1Title', 'Identidad sin fronteras', 'Identity without borders', 'Identité sans frontières') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.val1Text', 'Proyectamos lo mejor de México al mundo, celebrando nuestra cultura, talento y creatividad como puente de entendimiento entre naciones.', 'We project the best of Mexico to the world, celebrating our culture, talent and creativity as a bridge of understanding between nations.', 'Nous projetons le meilleur du Mexique au monde, célébrant notre culture, notre talent et notre créativité en tant que pont de compréhension entre les nations.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.val2Title', 'Liderazgo con propósito', 'Leadership with purpose', 'Un leadership avec un but') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.val2Text', 'Ponemos a las mujeres mexicanas al centro, impulsando su desarrollo económico, profesional y social como motor de transformación.', 'We put Mexican women at the center, promoting their economic, professional and social development as an engine of transformation.', 'Nous plaçons les femmes mexicaines au centre, en promouvant leur développement économique, professionnel et social comme moteur de transformation.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.val3Title', 'Conexión que trasciende', 'Connection that transcends', 'Une connexion qui transcende') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.val3Text', 'Construimos redes binacionales sólidas entre México y Canadá, generando oportunidades de negocio, colaboración y crecimiento mutuo.', 'We build solid binational networks between Mexico and Canada, generating business opportunities, collaboration and mutual growth.', 'Nous construisons de solides réseaux binationaux entre le Mexique et le Canada, générant des opportunités commerciales, une collaboration et une croissance mutuelle.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.val4Title', 'Impacto medible', 'Measurable impact', 'Impact mesurable') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.val4Text', 'Cada acción está diseñada para generar resultados concretos: exportaciones, alianzas estratégicas y proyectos de desarrollo sostenible.', 'Each action is designed to generate concrete results: exports, strategic alliances and sustainable development projects.', 'Chaque action est conçue pour générer des résultats concrets : exportations, alliances stratégiques et projets de développement durable.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.tlTitle', 'De la visión a la realidad', 'From vision to reality', 'De la vision à la réalité') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.tlDesc', 'Cada edición ha sido un paso firme hacia la consolidación de una comunidad binacional que impulsa el talento mexicano.', 'Each edition has been a firm step towards the consolidation of a binational community that promotes Mexican talent.', 'Chaque édition a été une étape décisive vers la consolidation d''une communauté binationale qui promeut les talents mexicains.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.milestone1Year', '2023', '2023', '2023') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.milestone1Title', 'Primera edición', 'First edition', 'Première édition') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.milestone1Text', 'Nacimiento de Expo México Mujer como plataforma para conectar el talento mexicano con oportunidades internacionales.', 'Birth of Expo México Mujer as a platform to connect Mexican talent with international opportunities.', 'Naissance d’Expo México Mujer en tant que plateforme permettant de connecter les talents mexicains aux opportunités internationales.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.milestone2Year', '2024', '2024', '2024') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.milestone2Title', 'Expansión binacional', 'Binational expansion', 'Expansion binationale') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.milestone2Text', 'Consolidación del evento con la participación de más de 12 industrias y la llegada de compradores canadienses.', 'Consolidation of the event with the participation of more than 12 industries and the arrival of Canadian buyers.', 'Consolidation de l''événement avec la participation de plus de 12 industries et l''arrivée d''acheteurs canadiens.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.milestone3Year', '2025', '2025', '2025') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.milestone3Title', 'Reconocimiento institucional', 'Institutional recognition', 'Reconnaissance institutionnelle') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.milestone3Text', 'Aliados estratégicos de gobierno, cámaras de comercio y organismos internacionales se suman al proyecto.', 'Strategic allies from the government, chambers of commerce and international organizations join the project.', 'Des alliés stratégiques du gouvernement, des chambres de commerce et des organisations internationales se joignent au projet.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.milestone4Year', '2027', '2027', '2027') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.milestone4Title', 'Edición histórica', 'Historical edition', 'Édition historique') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.nosotros.milestone4Text', 'Cinco días en Toronto con la participación de líderes, empresarias y creadoras que transforman el liderazgo mexicano en legado.', 'Five days in Toronto with the participation of leaders, businesswomen and creators who transform Mexican leadership into a legacy.', 'Cinq jours à Toronto avec la participation de leaders, de femmes d''affaires et de créateurs qui transforment le leadership mexicain en héritage.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.category', 'Servicios Binacionales // Canadá 2027', 'Binational Services // Canada 2027', 'Services binationaux // Canada 2027') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.introTitle', 'Gestión de Visas para Expositoras', 'Visa Management for Exhibitors', 'Gestion des visas pour les exposants') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.introText1', 'Viajar a Canadá representa una oportunidad comercial inmejorable para consolidar y expandir tu empresa en el mercado norteamericano. Sin embargo, contar con la documentación legal adecuada es el primer y más importante paso de tu planeación de viaje.', 'Traveling to Canada represents an unbeatable business opportunity to consolidate and expand your company in the North American market. However, having the proper legal documentation is the first and most important step in your travel planning.', 'Voyager au Canada représente une opportunité d''affaires imbattable pour consolider et développer votre entreprise sur le marché nord-américain. Cependant, disposer des documents juridiques appropriés est la première et la plus importante étape de la planification de votre voyage.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.introText2', 'En Expo México Mujer 2027, entendemos los retos administrativos que esto representa. Por ello, ponemos a tu disposición un equipo de consultores especializados en derecho migratorio canadiense para coordinar, revisar y dar seguimiento completo a tu trámite de visa.', 'At Expo México Mujer 2027, we understand the administrative challenges this represents. For this reason, we put at your disposal a team of consultants specialized in Canadian immigration law to coordinate, review and fully monitor your visa process.', 'À Expo México Mujer 2027, nous comprenons les défis administratifs que cela représente. Pour cette raison, nous mettons à votre disposition une équipe de consultants spécialisés en droit canadien de l''immigration pour coordonner, réviser et suivre entièrement votre processus de visa.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.alertTitle', 'Importante (Actualización de Viaje):', 'Important (Travel Update):', 'Important (mise à jour sur les voyages) :') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.alertDesc', 'A partir de 2024, el gobierno de Canadá ha reintroducido el requisito de Visa de Visitante para ciudadanos mexicanos. Si no cuentas con una visa americana vigente o visa canadiense previa en los últimos 10 años (requisitos para tramitar una eTA ágil), debes realizar un trámite completo de visa física. Te recomendamos iniciar tu solicitud hoy mismo.', 'Starting in 2024, the Government of Canada has reintroduced the Visitor Visa requirement for Mexican citizens. If you do not have a valid American visa or a previous Canadian visa in the last 10 years (requirements to process an agile eTA), you must complete a complete physical visa process. We recommend you start your application today.', 'À partir de 2024, le gouvernement du Canada a réintroduit l''exigence de visa de visiteur pour les citoyens mexicains. Si vous n''avez pas de visa américain valide ou de visa canadien antérieur au cours des 10 dernières années (exigences pour traiter une AVE agile), vous devez effectuer un processus de visa physique complet. Nous vous recommandons de commencer votre candidature dès aujourd''hui.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.metodologiaLabel', 'Metodología paso a paso', 'Step by step methodology', 'Méthodologie étape par étape') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.procesoTitle', 'El Proceso de Asesoría', 'The Consulting Process', 'Le processus de consultation') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.step1Title', 'Diagnóstico inicial', 'Initial diagnosis', 'Diagnostic initial') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.step1Desc', 'Analizamos tu historial de viajes y estatus actual. Evaluamos si eres elegible para una eTA (Autorización Electrónica de Viaje si tienes visa americana vigente) o si requieres una Visa de Visitante completa.', 'We analyze your travel history and current status. We evaluate if you are eligible for an eTA (Electronic Travel Authorization if you have a valid American visa) or if you require a full Visitor Visa.', 'Nous analysons votre historique de voyage et votre statut actuel. Nous évaluons si vous êtes éligible à une AVE (Autorisation de voyage électronique si vous avez un visa américain valide) ou si vous avez besoin d''un visa de visiteur complet.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.step2Title', 'Armado de expediente', 'File preparation', 'Préparation du dossier') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.step2Desc', 'Te proporcionamos un checklist personalizado de documentos. Revisamos tus pruebas de solvencia económica y arraigo en México, traduciendo y ordenando el expediente para cumplir con los estándares de IRCC.', 'We provide you with a personalized checklist of documents. We review your evidence of economic solvency and roots in Mexico, translating and organizing the file to comply with IRCC standards.', 'Nous mettons à votre disposition une liste de contrôle personnalisée des documents. Nous examinons vos preuves de solvabilité économique et de vos racines au Mexique, traduisons et organisons le dossier pour qu''il soit conforme aux normes d''IRCC.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.step3Title', 'Carga y pago consular', 'Consular charge and payment', 'Frais et paiement consulaires') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.step3Desc', 'Completamos los formularios oficiales en el portal del gobierno de Canadá y subimos tu expediente. Te apoyamos en el pago de derechos consulares ($185 CAD que incluyen el cargo de biometría).', 'We complete the official forms on the Canadian government portal and upload your file. We support you in the payment of consular fees ($185 CAD that includes the biometrics fee).', 'Nous remplissons les formulaires officiels sur le portail du gouvernement canadien et téléchargeons votre dossier. Nous vous accompagnons dans le paiement des frais consulaires (185$ CAD qui inclut les frais de biométrie).') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.step4Title', 'Toma de biometría', 'Taking biometrics', 'Prendre des données biométriques') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.step4Desc', 'Programamos tu cita en el Centro de Solicitud de Visas oficial (VFS Global) en CDMX, Monterrey o Guadalajara para la captura de tus huellas dactilares y fotografía digital.', 'We schedule your appointment at the official Visa Application Center (VFS Global) in CDMX, Monterrey or Guadalajara to capture your fingerprints and digital photograph.', 'Nous planifions votre rendez-vous au centre de demande de visa officiel (VFS Global) à CDMX, Monterrey ou Guadalajara pour capturer vos empreintes digitales et votre photo numérique.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.step5Title', 'Aprobación y estampado', 'Approval and stamping', 'Approbation et estampillage') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.step5Desc', 'Monitoreamos la respuesta de la embajada. Una vez aprobada, te guiamos en el envío seguro de tu pasaporte físico a través de mensajería autorizada para el estampado de la visa.', 'We monitor the embassy''s response. Once approved, we guide you in safely sending your physical passport through authorized courier for visa stamping.', 'Nous surveillons la réponse de l''ambassade. Une fois approuvé, nous vous guidons pour envoyer en toute sécurité votre passeport physique par courrier agréé pour le visa.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.organizerLabel', 'Organizador Personal', 'Personal Organizer', 'Organisateur personnel') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.requisitosGeneralesTitle', 'Requisitos Generales', 'General Requirements', 'Exigences générales') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.checklistDesc', 'Interactúa con el organizador haciendo clic en los requisitos que ya tengas listos para llevar control de tu expediente:', 'Interact with the organizer by clicking on the requirements that you already have ready to keep track of your file:', 'Interagissez avec l''organisateur en cliquant sur les exigences que vous avez déjà prêtes pour suivre votre dossier :') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.check1', 'Pasaporte mexicano con vigencia mínima de 6 meses posteriores al viaje.', 'Mexican passport valid for at least 6 months after the trip.', 'Passeport mexicain valable au moins 6 mois après le voyage.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.check2', 'Visa americana vigente (si aplica para solicitar la vía eTA ágil).', 'Valid American visa (if applicable to request the agile eTA route).', 'Visa américain valide (le cas échéant pour demander l''itinéraire agile eTA).') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.check3', 'Comprobantes de solvencia económica (estados de cuenta bancarios de los últimos 3 meses, nóminas o declaraciones de impuestos).', 'Proof of financial solvency (bank statements from the last 3 months, payslips or tax returns).', 'Preuve de solvabilité financière (relevés bancaires des 3 derniers mois, fiches de salaire ou déclarations fiscales).') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.check4', 'Documentos de arraigo en México (carta patronal de empleo, escrituras de propiedades, o constancias de estudios).', 'Documents of roots in Mexico (employment letter, property deeds, or study certificates).', 'Documents d''origine mexicaine (lettre de travail, actes de propriété ou certificats d''études).') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.check5', 'Carta de invitación oficial emitida por la dirección de Expo México Mujer 2027.', 'Official invitation letter issued by the management of Expo México Mujer 2027.', 'Lettre d''invitation officielle émise par la direction d''Expo México Mujer 2027.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.check6', 'Fotografía digital reciente que cumpla con los requisitos del gobierno canadiense.', 'Recent digital photograph that meets Canadian government requirements.', 'Photographie numérique récente répondant aux exigences du gouvernement canadien.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.faqLabel', 'Respuestas Directas', 'Direct Answers', 'Réponses directes') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.faqTitle', 'Preguntas Frecuentes', 'Frequently Asked Questions', 'Foire aux questions') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.faq1Q', '¿Cuánto tiempo tarda el proceso de aprobación de la visa canadiense?', 'How long does the Canadian visa approval process take?', 'Combien de temps prend le processus d''approbation d''un visa canadien ?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.faq1A', 'El procesamiento oficial del gobierno de Canadá (IRCC) suele tomar entre 4 y 8 semanas a partir de la toma de biometría. Recomendamos iniciar tu trámite al menos 3 meses antes de las fechas del evento (junio de 2027) para viajar con absoluta tranquilidad.', 'Official processing by the Government of Canada (IRCC) typically takes 4-8 weeks from biometrics collection. We recommend starting your process at least 3 months before the event dates (June 2027) to travel with absolute peace of mind.', 'Le traitement officiel par le gouvernement du Canada (IRCC) prend généralement de 4 à 8 semaines à compter de la collecte des données biométriques. Nous vous recommandons de démarrer votre démarche au moins 3 mois avant les dates de l''événement (juin 2027) pour voyager en toute sérénité.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.faq2Q', '¿Quiénes son elegibles para ingresar a Canadá con una eTA rápida?', 'Who is eligible to enter Canada with an express eTA?', 'Qui est admissible à entrer au Canada avec une AVE express ?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.faq2A', 'Puedes tramitar una eTA (que se aprueba en minutos u horas) si viajas por vía aérea y cumples con alguno de estos requisitos: 1) Tienes una visa de no inmigrante de EE.UU. vigente (visa de turista), o 2) Tuviste una visa de visitante canadiense en los últimos 10 años. Si ingresas por tierra o no tienes estos documentos, necesitas tramitar una visa de visitante completa.', 'You can apply for an eTA (which is approved in minutes or hours) if you are traveling by air and meet any of these requirements: 1) You have a current US non-immigrant visa (tourist visa), or 2) You had a Canadian visitor visa in the last 10 years. If you enter by land or do not have these documents, you need to apply for a full visitor visa.', 'Vous pouvez demander une AVE (qui est approuvée en quelques minutes ou heures) si vous voyagez par avion et remplissez l''une de ces conditions : 1) Vous avez un visa américain de non-immigrant en cours (visa touristique), ou 2) Vous avez eu un visa de visiteur canadien au cours des 10 dernières années. Si vous entrez par voie terrestre ou si vous ne disposez pas de ces documents, vous devez demander un visa de visiteur complet.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.faq3Q', '¿Qué costos consulares debo pagar directamente al gobierno de Canadá?', 'What consular costs do I have to pay directly to the Canadian government?', 'Quels frais consulaires dois-je payer directement au gouvernement canadien ?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.faq3A', 'La solicitud de Visa de Visitante completa cuesta $100 CAD más $85 CAD por la toma de datos biométricos (total de $185 CAD). Si eres elegible para eTA, el costo es de únicamente $7 CAD. Estos cargos se pagan con tarjeta directamente en el portal oficial canadiense.', 'The complete Visitor Visa application costs $100 CAD plus $85 CAD for biometric data collection (total $185 CAD). If you are eligible for eTA, the cost is only $7 CAD. These charges are paid by card directly on the official Canadian portal.', 'La demande complète de visa de visiteur coûte 100 $ CAD plus 85 $ CAD pour la collecte de données biométriques (total 185 $ CAD). Si vous êtes admissible à l’AVE, le coût est de seulement 7 $ CAD. Ces frais sont payés par carte directement sur le portail officiel canadien.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.faq4Q', '¿El servicio de gestoría me garantiza la aprobación de mi visa?', 'Does the agency service guarantee the approval of my visa?', 'Le service de l''agence garantit-il l''approbation de mon visa ?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.faq4A', 'La decisión final de emitir una visa es facultad exclusiva de los oficiales consulares del gobierno de Canadá. Nuestro servicio optimiza tu expediente, asegurando que no haya errores de llenado, que las traducciones sean correctas y que la justificación de tu viaje, arraigo y solvencia esté estructurada con la mayor solidez posible, maximizando las probabilidades de éxito.', 'The final decision to issue a visa is the sole discretion of consular officers of the Government of Canada. Our service optimizes your file, ensuring that there are no filling errors, that the translations are correct and that the justification of your trip, residence and solvency is structured as solidly as possible, maximizing the chances of success.', 'La décision finale de délivrer un visa est à la seule discrétion des agents consulaires du gouvernement du Canada. Notre service optimise votre dossier, en s''assurant qu''il n''y a pas d''erreurs de remplissage, que les traductions sont correctes et que la justification de votre voyage, de votre résidence et de votre solvabilité est structurée le plus solidement possible, maximisant ainsi les chances de succès.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.faq5Q', '¿Expo México Mujer emite cartas de invitación para el trámite?', 'Does Expo México Mujer issue invitation letters for the procedure?', 'Expo México Mujer envoie-t-elle des lettres d''invitation pour la procédure ?') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.faq5A', 'Sí. Emitimos cartas de invitación personalizadas de carácter oficial de negocios y participación para todas las expositoras confirmadas, patrocinadores y conferencistas. Este documento oficial es un elemento de soporte clave ante el oficial consular.', 'Yes. We issue personalized invitation letters of an official business and participation nature to all confirmed exhibitors, sponsors and speakers. This official document is a key support element before the consular officer.', 'Oui. Nous envoyons des lettres d''invitation personnalisées à caractère officiel d''affaires et de participation à tous les exposants, sponsors et conférenciers confirmés. Ce document officiel est un élément d’appui clé devant le fonctionnaire consulaire.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.contactoLabel', 'Contacto Inmediato', 'Immediate Contact', 'Contact immédiat') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.iniciaSolicitud', 'Inicia tu Solicitud', 'Start your Application', 'Démarrez votre candidature') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.solicitudDesc', 'Completa el formulario en el panel derecho con tus datos básicos. Un asesor de visas de Expo México Mujer revisará tu perfil de forma gratuita y te contactará en un plazo menor a 24 horas vía WhatsApp o correo electrónico para agendar tu llamada diagnóstica.', 'Complete the form in the right panel with your basic information. A visa advisor from Expo México Mujer will review your profile for free and contact you within 24 hours via WhatsApp or email to schedule your diagnostic call.', 'Remplissez le formulaire dans le panneau de droite avec vos informations de base. Un conseiller en visas d''Expo México Mujer examinera votre profil gratuitement et vous contactera dans les 24 heures via WhatsApp ou par e-mail pour planifier votre appel de diagnostic.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.tiempoRespuesta', 'Tiempo de Respuesta', 'Response Time', 'Temps de réponse') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
