INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.mensajePlaceholder', 'Escribe aquí si tienes alguna duda en particular sobre tus documentos o historial...', 'Write here if you have any particular questions about your documents or history...', 'Écrivez ici si vous avez des questions particulières sur vos documents ou votre historique...') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
