INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.completaCampos', 'Por favor completa todos los campos requeridos.', 'Please complete all required fields.', 'Veuillez remplir tous les champs obligatoires.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.exitoTitle', '¡Solicitud Registrada!', 'Registered Application!', 'Candidature enregistrée !') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.exitoDesc', 'Gracias por tu confianza. Hemos recibido tus datos correctamente. Uno de nuestros consultores certificados te enviará un diagnóstico inicial por WhatsApp o Correo en las próximas horas.', 'Thank you for your trust. We have received your information correctly. One of our certified consultants will send you an initial diagnosis by WhatsApp or Email in the next few hours.', 'Merci pour votre confiance. Nous avons reçu vos informations correctement. Un de nos consultants certifiés vous enverra un premier diagnostic par WhatsApp ou Email dans les prochaines heures.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.visa.terminosText', 'Al enviar esta solicitud, aceptas nuestros', 'By submitting this request, you agree to our', 'En soumettant cette demande, vous acceptez notre') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
