INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.intro.title', 'Una plataforma que trasciende fronteras ', 'A platform that transcends borders ', 'Une plateforme qui transcende les frontières ') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.intro.p1', 'Expo México Mujer es el encuentro empresarial y cultural más relevante entre México y Canadá. Nace de la necesidad de proyectar el liderazgo y talento corporativo femenino de origen mexicano hacia mercados norteamericanos de alta competitividad.', 'Expo México Mujer is the most relevant business and cultural meeting between Mexico and Canada. It was born from the need to project female corporate leadership and talent of Mexican origin towards highly competitive North American markets.', 'Expo México Mujer est la rencontre commerciale et culturelle la plus importante entre le Mexique et le Canada. Elle est née de la nécessité de projeter le leadership féminin et les talents d''origine mexicaine vers des marchés nord-américains hautement compétitifs.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.intro.p2', 'Durante 5 días en la metrópoli de Toronto, el evento reúne a delegadas de múltiples estados mexicanos con compradores globales, inversionistas institucionales y autoridades consulares en una serie de foros de alto nivel, pasarelas de moda y mesas de negociación directa.', 'Over 5 days in the Toronto metropolis, the event brings together delegates from multiple Mexican states with global buyers, institutional investors and consular authorities in a series of high-level forums, fashion catwalks and direct negotiation tables.', 'Pendant 5 jours dans la métropole de Toronto, l''événement rassemble des délégués de plusieurs États mexicains avec des acheteurs mondiaux, des investisseurs institutionnels et des autorités consulaires dans une série de forums de haut niveau, de défilés de mode et de tables de négociation directe.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.impact.title', 'Impacto México-Canadá', 'Mexico-Canada Impact', 'Impact Mexique-Canada') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.impact.i1.title', 'Alianza Binacional', 'Binational Alliance', 'Alliance binationale') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.impact.i1.desc', 'Fortalecimiento del comercio internacional directo al amparo del acuerdo del T-MEC.', 'Strengthening direct international trade under the T-MEC agreement.', 'Renforcement du commerce international direct dans le cadre de l’accord T-MEC.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.impact.i2.title', 'Proyección Cultural', 'Cultural Projection', 'Projection culturelle') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.impact.i2.desc', 'Difusión artística, textil y artesanal de alta gama en espacios museísticos y comerciales de Canadá.', 'High-end artistic, textile and craft dissemination in museum and commercial spaces in Canada.', 'Diffusion artistique, textile et artisanale haut de gamme dans les musées et espaces commerciaux au Canada.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.impact.i3.title', 'Empoderamiento Económico', 'Economic Empowerment', 'Autonomisation économique') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.impact.i3.desc', 'Impulso al crecimiento empresarial de mujeres mexicanas a través de redes de mentoría y acceso a financiamiento internacional.', 'Promoting business growth for Mexican women through mentoring networks and access to international financing.', 'Promouvoir la croissance des entreprises pour les femmes mexicaines grâce à des réseaux de mentorat et à l’accès au financement international.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.mision.title', 'Misión, Visión y Objetivos', 'Mission, Vision and Objectives', 'Mission, vision et objectifs') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.mision.m1.title', 'Misión', 'Mission', 'Mission') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.mision.m1.desc', 'Empoderar a la mujer empresaria y profesional de origen mexicano facilitando su inserción, posicionamiento e impacto en los mercados internacionales, especialmente en Canadá.', 'Empower business and professional women of Mexican origin by facilitating their insertion, positioning and impact in international markets, especially in Canada.', 'Autonomiser les femmes d''affaires et professionnelles d''origine mexicaine en facilitant leur insertion, leur positionnement et leur impact sur les marchés internationaux, notamment au Canada.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.mision.m2.title', 'Visión', 'Vision', 'Vision') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.mision.m2.desc', 'Ser la plataforma líder de vinculación empresarial y cultural para mujeres hispanas en Norteamérica, reconocida por su excelencia, impacto socioeconómico y resultados tangibles.', 'To be the leading business and cultural networking platform for Hispanic women in North America, recognized for its excellence, socioeconomic impact and tangible results.', 'Être la principale plateforme de réseautage commercial et culturel pour les femmes hispaniques en Amérique du Nord, reconnue pour son excellence, son impact socio-économique et ses résultats tangibles.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.mision.m3.title', 'Objetivos', 'Goals', 'Objectifs') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.queEs.mision.m3.desc', 'Generar alianzas comerciales sostenibles, brindar herramientas técnicas de capacitación global y proyectar el patrimonio e identidad cultural de México al más alto nivel.', 'Generate sustainable business alliances, provide global training technical tools and project Mexico''s cultural heritage and identity at the highest level.', 'Générer des alliances commerciales durables, fournir des outils techniques de formation mondiaux et projeter le patrimoine culturel et l''identité du Mexique au plus haut niveau.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
