INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.industrias.intro.title', 'Sectores que impulsan el desarrollo binacional', 'Sectors that promote binational development', 'Des secteurs qui favorisent le développement binational') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.industrias.intro.p', 'La delegación empresarial de Expo México Mujer Toronto 2027 abarca 12 industrias clave. Cada pabellón está organizado estratégicamente para facilitar el flujo de compradores canadienses e inversionistas norteamericanos interesados en expandir sus redes de proveedores y socios comerciales.', 'The Expo México Mujer Toronto 2027 business delegation covers 12 key industries. Each pavilion is strategically organized to facilitate the flow of Canadian buyers and North American investors interested in expanding their networks of suppliers and business partners.', 'La délégation commerciale de l''Expo México Mujer Toronto 2027 couvre 12 industries clés. Chaque pavillon est organisé stratégiquement pour faciliter la circulation des acheteurs canadiens et des investisseurs nord-américains intéressés à élargir leurs réseaux de fournisseurs et de partenaires commerciaux.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.industrias.ventajas.title', 'Ventajas de Participación', 'Advantages of Participation', 'Avantages de la participation') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.industrias.ventajas.i1', 'Ruedas de negocios B2B personalizadas.', 'Customized B2B business conferences.', 'Conférences d''affaires B2B sur mesure.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.industrias.ventajas.i2', 'Espacio de exhibición comercial en la sede central de Toronto.', 'Commercial exhibition space at Toronto headquarters.', 'Espace d''exposition commerciale au siège social de Toronto.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
