INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.ottawa2026.intro.title', 'El gran precedente en la capital canadiense', 'The great precedent in the Canadian capital', 'Le grand précédent dans la capitale canadienne') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.ottawa2026.intro.p1', 'La edición de **Expo México Mujer Ottawa 2026** marcó un hito en las relaciones comerciales binacionales independientes. Durante tres días intensivos en el centro neurálgico de la capital de Canadá, consolidamos una plataforma que conectó la herencia, creatividad y capacidad productiva mexicana con redes de distribución norteamericanas.', 'The edition of **Expo México Mujer Ottawa 2026** marked a milestone in independent binational trade relations. During three intensive days in the nerve center of Canada''s capital, we consolidated a platform that connected Mexican heritage, creativity and productive capacity with North American distribution networks.', 'L''édition de **Expo México Mujer Ottawa 2026** a marqué une étape importante dans les relations commerciales binationales indépendantes. Pendant trois jours intensifs au centre névralgique de la capitale canadienne, nous avons consolidé une plateforme reliant l''héritage, la créativité et la capacité de production mexicains aux réseaux de distribution nord-américains.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.ottawa2026.intro.p2', 'Esta edición fue respaldada por embajadores, senadores, cámaras de comercio binacionales y cooperativas de empresarias, sentando las bases operativas, logísticas y de mercado para la próxima edición central de Toronto 2027.', 'This edition was supported by ambassadors, senators, binational chambers of commerce and business cooperatives, laying the operational, logistical and market foundations for the next central edition of Toronto 2027.', 'Cette édition a été soutenue par des ambassadeurs, des sénateurs, des chambres de commerce binationales et des coopératives d''affaires, posant les bases opérationnelles, logistiques et commerciales de la prochaine édition centrale de Toronto 2027.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.expo.ottawa2026.detalles.title', 'Detalles de la Edición', 'Edition Details', 'Détails de l''édition') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
