INSERT INTO translations (translation_key, text_es, text_en, text_fr) VALUES ('pages.contactoInfo.desc', 'Nuestros canales oficiales de comunicación están a su disposición para resolver cualquier duda técnica, comercial o de logística respecto a Expo México Mujer.', 'Our official communication channels are at your disposal to resolve any technical, commercial or logistical questions regarding Expo México Mujer.', 'Nos canaux de communication officiels sont à votre disposition pour résoudre toute question technique, commerciale ou logistique concernant Expo México Mujer.') ON CONFLICT (translation_key) DO UPDATE SET text_es = EXCLUDED.text_es, text_en = EXCLUDED.text_en, text_fr = EXCLUDED.text_fr;
