INSERT INTO business_cards (id, slug, name, title, company, bio, photo, email, phone, whatsapp, website, linkedin, instagram, vcard_url) VALUES ('1', 'francisco-solorio', 'Francisco Solorio', 'Director General', 'Expo México Mujer', 'Soy especialista en cooperación internacional y desarrollo de alianzas estratégicas. Como Director General de Expo México Mujer, lidero una plataforma internacional que impulsa el talento y emprendimiento de las mujeres entre México y Canadá.', '/fotos perfil/Foto Francisco.jpg', 'francisco@expomexico.ca', '+52 55 2719 9694', '525527199694', 'expomexico.ca', 'https://linkedin.com/in/francisco-solorio', 'https://instagram.com/expomexico_mujer', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name;
INSERT INTO business_cards (id, slug, name, title, company, bio, photo, email, phone, whatsapp, website, linkedin, instagram, vcard_url) VALUES ('2', 'luis-garcia', 'Luis García González', 'Director de Operaciones México–Canadá', 'Expo México Mujer', 'Soy experto en cooperación internacional y gestión estratégica. Como Director de Operaciones México–Canadá de Expo México Mujer, lidero la coordinación operativa con una visión de sostenibilidad e inclusión.', '/fotos perfil/Foto Luis.jpg', 'luis@expomexico.ca', '+52 722 551 4645', '527225514645', 'expomexico.ca', 'https://linkedin.com/in/luis-garcia', 'https://instagram.com/expomexico_mujer', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name;
